SELECT c.employee_id, pe.work_card, c.date, pe.name, pe.gender, fdev.ext_dept_name, fdev.ext_department_name, fdev.ext_team_name, -- d.clockDiff, -- d.overTime, CONVERT ( VARCHAR ( 8 ), c.clock_time ) clock_times, c.card_machine_no as attendance_machine -- d.nextDATE FROM ( SELECT acr.id, acr.employee_id, acr.date, acr.create_time, acr.clock_time, acr.card_machine_no, ROW_NUMBER ( ) OVER ( ORDER BY DATE DESC, acr.employee_id DESC ) AS RowNum, pe.work_card, pe.name, pe.gender, fdev.ext_dept_name, fdev.ext_department_name, fdev.ext_team_name FROM ac_clock_record acr JOIN pm_employee as pe ON pe.id = acr.employee_id JOIN pm_employee_job as pej ON pej.employee_id = pe.id JOIN fnd_dept_ext_v fdev on pej.dept_id=fdev.id where 1 = 1 --AND --pe.work_card = '003104' AND
and pej.dept_id = #{criteria.deptId,jdbcType=BIGINT}
and acr.date BETWEEN #{criteria.beginDate, jdbcType = DATE} and #{criteria.endDate, jdbcType = DATE}
) AS c JOIN pm_employee as pe ON pe.id = c.employee_id JOIN pm_employee_job pej ON pej.employee_id = pe.id JOIN fnd_dept_ext_v fdev on pej.dept_id=fdev.id -- CROSS APPLY (SELECT * FROM dbo.get_pre_next_date(c.date, c.employee_id)) AS d WHERE 1 = 1 AND c.RowNum BETWEEN (#{page} - 1) * 100 + 1 AND (#{page} * #{pageSize} * 2) ORDER BY c.date desc;

SELECT top 1200 c.employee_id, pe.work_card, c.date, pe.name, pe.gender, fdev.ext_dept_name, fdev.ext_department_name, fdev.ext_team_name, -- d.clockDiff, -- d.overTime, CONVERT ( VARCHAR ( 8 ), c.clock_time ) clock_times, c.card_machine_no as attendance_machine -- d.nextDATE FROM ( SELECT acr.id, acr.employee_id, acr.date, acr.create_time, acr.clock_time, acr.card_machine_no, ROW_NUMBER ( ) OVER ( ORDER BY DATE DESC, acr.employee_id DESC ) AS RowNum, pe.work_card, pe.name, pe.gender, fdev.ext_dept_name, fdev.ext_department_name, fdev.ext_team_name FROM ac_clock_record acr JOIN pm_employee as pe ON pe.id = acr.employee_id JOIN pm_employee_job as pej ON pej.employee_id = pe.id JOIN fnd_dept_ext_v fdev on pej.dept_id=fdev.id where 1 = 1 --AND --pe.work_card = '003104' AND
and pej.dept_id = #{criteria.deptId,jdbcType=BIGINT}
and acr.date BETWEEN #{criteria.beginDate, jdbcType = DATE} and #{criteria.endDate, jdbcType = DATE}
) AS c JOIN pm_employee as pe ON pe.id = c.employee_id JOIN pm_employee_job pej ON pej.employee_id = pe.id JOIN fnd_dept_ext_v fdev on pej.dept_id=fdev.id -- CROSS APPLY (SELECT * FROM dbo.get_pre_next_date(c.date, c.employee_id)) AS d WHERE 1 = 1 AND c.RowNum BETWEEN 0 + 1 AND 1500 ORDER BY c.date desc;
